#include <bits/stdc++.h>
using namespace std;
const int N=55;
int n,m,a[N][N],f[2*N][N][N];
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            scanf("%d",&a[i][j]);
    memset(f,0xcf,sizeof(f));
    f[2][1][1]=0;
    for(int i=3;i<=n+m;i++){
        for(int j=1;j<=n;j++)
            for(int k=j+(i<n+m);k<=n;k++){
                int p=i-j,q=i-k;
                if(p<0 || p>m || q<0 || q>m)
                    continue;
                f[i][j][k]=max(max(f[i-1][j][k],f[i-1][j-1][k]),max(f[i-1][j][k-1],f[i-1][j-1][k-1]))+a[j][p]+a[k][q];
            }
    }
    printf("%d",f[n+m][n][n]);
    return 0;
}
